const raw = $input.first().json.body;
const data = typeof raw === 'string' ? JSON.parse(raw.replace(/^=\s*/, '').trim()) : raw;
return [{ json: data }];

const raw = $input.first().json.content[0].text;
let classification;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  classification = match ? JSON.parse(match[0]) : {};
} catch(e) {
  classification = { urgencia: 'warm', intencion: 'investigando', calidad: 'media', prioridad: 3, resumen_equipo: 'Error al clasificar', accion_recomendada: 'Revisar manualmente' };
}

const lead = $('Parsear Body').first().json;

return [{
  json: {
    ...classification,
    lead_name: lead.name,
    lead_phone: lead.phone,
    service_name: lead.service_name,
    city_interest: lead.city_interest,
    message: lead.message,
    utm_source: lead.utm_source
  }
}];
